// Parse INVOICE_EXTRACTED event payload from MX_00
const body = $input.first().json.body || $input.first().json;
const payload = body.payload || body;

// Parse positionen if it's a string
let positionen = payload.positionen || [];
if (typeof positionen === 'string') {
  try { positionen = JSON.parse(positionen); } catch(e) { positionen = []; }
}

return {
  json: {
    event_id: body.event_id || body.id,
    invoice_id: payload.invoice_id,
    extraction_source: payload.extraction_source || 'ATTACHMENT',
    storage_path: payload.storage_path || '',
    rechnung_nummer: payload.rechnung_nummer || '',
    rechnung_datum: payload.rechnung_datum || new Date().toISOString().split('T')[0],
    lieferant_name: payload.lieferant_name || '',
    lieferant_name_escaped: payload.lieferant_name_escaped || (payload.lieferant_name || '').replace(/'/g, "''"),
    summe_netto: payload.summe_netto || 0,
    summe_brutto: payload.summe_brutto || 0,
    mwst_prozent: payload.mwst_prozent || 19,
    positionen: positionen,
    positionen_count: payload.positionen_count || positionen.length || 0,
    payment_iban: payload.payment_iban || '',
    payment_bic: payload.payment_bic || '',
    payment_terms_days: payload.payment_terms_days || 14,
    due_date: payload.due_date || '',
    discount_percent: payload.discount_percent || 0,
    discount_days: payload.discount_days || 0,
    project_reference: payload.project_reference || '',
    delivery_address: payload.delivery_address || '',
    expense_category: payload.expense_category || 'MATERIAL',
    email_from: payload.email_from || '',
    email_subject: (payload.email_subject || '').replace(/'/g, "''"),
    email_received_at: payload.email_received_at || new Date().toISOString(),
    superchat_message_id: payload.superchat_message_id || '',
    doc_type: payload.doc_type || 'INVOICE_IN',
    invoice_type: payload.invoice_type || 'invoice',
    original_filename: payload.original_filename || '',
    needs_assignment: payload.needs_assignment || false,
  }
};

