// Split positions + generate SKU for product pool
const positions = $('📥 Parse Event').first().json.positionen || [];
const invoiceId = $('📄 Create Invoice').first().json.id;
const supplierId = $('🏢 Match Supplier').first().json.supplier_id;
const invoiceDate = $('📥 Parse Event').first().json.rechnung_datum;

// Hash für Artikel ohne SKU
const simpleHash = (str) => {
  let hash = 0;
  for (let i = 0; i < str.length; i++) {
    const char = str.charCodeAt(i);
    hash = ((hash << 5) - hash) + char;
    hash = hash & hash;
  }
  return 'GEN-' + Math.abs(hash).toString(16).toUpperCase().substring(0, 8);
};

return positions.map((pos, idx) => {
  const description = (pos.beschreibung || 'Unbekannt').replace(/'/g, "''");
  const articleNumber = pos.artikel_nummer || '';
  const sku = articleNumber || simpleHash(description + supplierId);

  return {
    json: {
      invoice_id: invoiceId,
      supplier_id: supplierId,
      position_number: idx + 1,
      article_number: articleNumber,
      description: description,
      quantity: pos.menge || 1,
      unit: pos.einheit || 'Stk',
      unit_price_net: Math.round((Number(pos.einzelpreis_brutto) || 0) / 1.19 * 100) / 100,
      product_sku: sku,
      product_category: pos.kategorie || null,
      invoice_date: invoiceDate
    }
  };
});
